<template>
  <div class="card-program-header">
    <WaveContainer :title="'Chủ đề ' + chude.id" :description="chude.name" />
  </div>

  <div class="card-program-body">
    <ProgramItem
      v-for="baihoc in danhsachbaihoc"
      :linkTo="'chi-tiet-bai-hoc.html?id=' + baihoc.id "
      :key="baihoc.id"
      :thumbnailName="baihoc.thumbnail"
      :numbering="'Bài ' + baihoc.id"
      :title="baihoc.name"
    />
  </div>
</template>

<script>
import chudeData from "@/assets/data/chude.json";
import baihocData from "@/assets/data/baihoc.json";
import WaveContainer from "./WaveContainer.vue";
import ProgramItem from "./ProgramItem.vue";

const urlParams = new URLSearchParams(window.location.search);
let idChuDe = urlParams.get('id');
if (idChuDe == null) idChuDe = 1;
let currentChuDe = chudeData.find((chude) => chude.id == idChuDe);
let baihocOfChuDe = baihocData.reduce((filtered, baihoc) => {
  if (baihoc.idchude === currentChuDe.id) {
    let filteredBaiHoc = Object.assign({}, baihoc);
    filtered.push(filteredBaiHoc);
  }
  return filtered;
}, []);
export default {
  name: "CardChuDe",
  components: {
    WaveContainer,
    ProgramItem,
  },
  props: {},
  data() {
    return {
      chude: currentChuDe,
      danhsachbaihoc: baihocOfChuDe,
    };
  },
};
</script>

