<template>
  <div class="header">
    <div class="inner-header">
      <ul
        class="inner-header-list"
        style="width: 66.66%; justify-content: start"
      >
        <li class="inner-header-item">
          <a href="/"> <i class="fa-solid fa-house"></i> Trang chủ </a>
        </li>
        <li class="inner-header-item">
          <a href="/chu-de.html"> <i class="fa-solid fa-tags"></i> Chủ đề </a>
        </li>
        <li class="inner-header-item dropdown">
          <button @mouseover="showGames" @mouseleave="hideGames" class="dropbtn">
            <i class="fa-solid fa-pen-to-square"></i> Luyện tập
          </button>
          <div id="myDropdown" class="dropdown-content"  :class="{ 'show': gameVisible }">
            <a
              v-for="game in danhsachgame"
              :key="game.id"
              :href="'/tro-choi.html?id=' + game.id"
            >
              {{ game.name }}
            </a>
          </div>
        </li>
        <!-- <li class="inner-header-item"><a href="">
            <i class="fa-solid fa-hourglass-half"></i> Kiểm tra
          </a></li> -->
      </ul>
      <ul class="inner-header-list" style="width: 33.33%; justify-content: end">
        <li class="inner-header-item">
          <a href="/tai-nguyen.html">
            Tài nguyên <i class="fa-solid fa-box-open"></i>
          </a>
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
import gameData from "@/assets/data/game.json";

export default {
  name: "HeaderMenu",
  props: {},
  data() {
    return {
      danhsachgame: gameData,
      gameVisible: false,
    };
  },
  methods: {
    showGames() {
      this.gameVisible = !this.gameVisible;
    },
    hideGames() {
      this.gameVisible = false;
    },
  },
  mounted() {
    window.addEventListener("click", (event) => {
      if (!event.target.matches(".dropbtn")) {
        this.gameVisible = false;
      }
    });
  },
};
</script>

<style scoped>
.show {
  display: block;
}
/* Show the dropdown menu (use JS to add this class to the .dropdown-content container when the user clicks on the dropdown button) */
/* .show {
  display: block;
} */
</style>
